dslRule:
@id: jdt.internal.folding.skiplws.boundscheck
@severity: info
Character.isWhitespace(source[start])
:: inClass("org.eclipse.jdt.ui.text.folding.DefaultJavaFoldingStructureProvider") && inMethod("skipLeadingWhitespace")
=> start < source.length && Character.isWhitespace(source[start])
;;

@id: jdt.internal.ui.images.png-to-svg.move-up
@severity: info
createUnManaged($type, "move_up.png")
=> createUnManaged($type, "move_up.svg")
;;

@id: jdt.internal.ui.images.png-to-svg.newrecord-wiz
